    "learningCards": [
      {
        "title": "Understanding Cyber Threats",
        "content": "Cyber threats are diverse and evolving, impacting individuals and organizations alike.",
        "layout": "standard"
      },
      {
        "title": "Types of Threat Actors",
        "content": "- **State Sponsored Actors**: Target critical infrastructure with advanced techniques.\n- **Cybercriminals**: Driven by profit, often using ransomware and phishing.\n- **Hacktivists**: Motivated by political or social causes, aiming to disrupt services.",
        "layout": "bullet"
      },
      {
        "title": "Common Threats in the Landscape",
        "content": "- **Malware**: Software designed to disrupt, damage, or gain unauthorized access.\n- **Phishing**: Deceptive attempts to obtain sensitive information.\n- **DDoS Attacks**: Overwhelming a service to make it unavailable.",
        "layout": "bullet"
      },
      {
        "title": "Defensive Strategies",
        "content": "- **Regular Updates**: Keep systems and software up-to-date to mitigate vulnerabilities.\n- **User Education**: Train users to recognize and respond to threats.\n- **Incident Response Plans**: Prepare for potential breaches with clear action steps.",
        "layout": "bullet"
      }
    ]
  }
}
